module RefModule(
	input [31:0] inALUOut,
	input reset, clk,
	output [31:0] outALUOut
    );reg [31:0] registerALUOut;
  wire [31:0] _tap_inALUOut = inALUOut & {32{1'b1}};


	assign outALUOut = registerALUOut;

	always@(posedge clk)
		begin
			if (reset)
				begin
					registerALUOut <= 32'b0;
				end
			else
				begin
					registerALUOut <= inALUOut;
				end
		end

endmodule
